sql:
SELECT year, avg_refs_in_patents
FROM patent_statistics
WHERE avg_refs_in_patents > 10;

external_knowledge:
- Patent statistics are a measure of innovation and economic impact; 
- The country code 'US' refers to the United States; 
- GDP (Gross Domestic Product) is a monetary measure of the market value of all the final goods and services produced in a specific time period by country.

sql:
SELECT year, avg_cites_to_papers
   FROM patent_statistics
   ORDER BY year ASC;

SELECT year, total_patents, total_citations
FROM patent_statistics
WHERE year = 2023;

SELECT avg_cites_to_papers AS average_citations_per_family
FROM patent_statistics
WHERE year = 2000;

SELECT family_size
FROM patent_families
WHERE year = 2000;

SELECT AVG(gdp_value) AS average_gdp_value, gdp_year
FROM gdp_data
WHERE gdp_year = 1;

SELECT year
FROM patent_statistics
WHERE total_patents = (SELECT MAX(total_patents) FROM patent_statistics);

SELECT year, patent_families
FROM patent_statistics
WHERE year >= 2010;
